values.code:
var urls = {{triggerNode_1.output.job_urls}};
var out = [];
var i = 0;
while (i < urls.length) {
  var url = urls[i];
  var text = "";
  var status = "ok";
  try {
    var response = await fetch(url);
    var html = await response.text();
    var clean = html;
    var s1 = clean.indexOf('<script');
    while (s1 > -1) {
      var e1 = clean.indexOf('<' + '/script>', s1);
      if (e1 === -1) { break; }
      clean = clean.substring(0, s1) + ' ' + clean.substring(e1 + 9);
      s1 = clean.indexOf('<script');
    }
    var s2 = clean.indexOf('<style');
    while (s2 > -1) {
      var e2 = clean.indexOf('<' + '/style>', s2);
      if (e2 === -1) { break; }
      clean = clean.substring(0, s2) + ' ' + clean.substring(e2 + 8);
      s2 = clean.indexOf('<style');
    }
    var t1 = clean.indexOf('<');
    while (t1 > -1) {
      var t2 = clean.indexOf('>', t1);
      if (t2 === -1) { break; }
      clean = clean.substring(0, t1) + ' ' + clean.substring(t2 + 1);
      t1 = clean.indexOf('<');
    }
    var words = clean.split(' ');
    var filtered = [];
    var w = 0;
    while (w < words.length) {
      var word = words[w].trim();
      if (word.length > 0) { filtered.push(word); }
      w = w + 1;
    }
    text = filtered.join(' ');
    if (text.length > 6000) { text = text.substring(0, 6000); }
  } catch (e) {
    status = "error";
    text = "";
  }
  out.push({ url: url, jd_text: text, status: status });
  i = i + 1;
}
return { job_pages: out };

prompts.content:
Extract information from this job posting. Return job_title, company, location, seniority, required_skills as a comma separated string, preferred_skills as a comma separated string, responsibilities as a comma separated string, qualifications as a comma separated string.
Job posting:
{{forLoopNode_787.currentValue.jd_text}}

values.code:
var candidateSkills = {{InstructorLLMNode_426.output.skills}};
var jobRequiredRaw = {{InstructorLLMNode_219.output.required_skills}};
var jobPreferredRaw = {{InstructorLLMNode_219.output.preferred_skills}};
var jobTitle = {{InstructorLLMNode_219.output.job_title}};
var jobCompany = {{InstructorLLMNode_219.output.company}};
var jobSeniority = {{InstructorLLMNode_219.output.seniority}};

var jobRequired = jobRequiredRaw.split(',');
var jobPreferred = jobPreferredRaw.split(',');
var candidateList = candidateSkills.split(',');

var reqMatches = 0;
var prefMatches = 0;
var matchedSkills = [];
var i = 0;

while (i < jobRequired.length) {
  var req = jobRequired[i].toLowerCase().trim();
  var j = 0;
  while (j < candidateList.length) {
    var cs = candidateList[j].toLowerCase().trim();
    if (cs === req || cs.indexOf(req) > -1 || req.indexOf(cs) > -1) {
      reqMatches = reqMatches + 1;
      matchedSkills.push(candidateList[j].trim());
      break;
    }
    j = j + 1;
  }
  i = i + 1;
}

i = 0;
while (i < jobPreferred.length) {
  var pref = jobPreferred[i].toLowerCase().trim();
  var k = 0;
  while (k < candidateList.length) {
    var cs2 = candidateList[k].toLowerCase().trim();
    if (cs2 === pref || cs2.indexOf(pref) > -1 || pref.indexOf(cs2) > -1) {
      prefMatches = prefMatches + 1;
      matchedSkills.push(candidateList[k].trim());
      break;
    }
    k = k + 1;
  }
  i = i + 1;
}

var reqScore = jobRequired.length > 0 ? (reqMatches / jobRequired.length) * 70 : 35;
var prefScore = jobPreferred.length > 0 ? (prefMatches / jobPreferred.length) * 30 : 15;
var score = Math.round(reqScore + prefScore);

return {
  job_title: jobTitle,
  company: jobCompany,
  seniority: jobSeniority,
  score: score,
  qualified: score >= 70,
  matched_skills: matchedSkills.join(', ')
};

