});

var qualCount = 0;
var q = 0;
while (q < sorted.length) {
  if (sorted[q].qualified === true) { qualCount = qualCount + 1; }
  q = q + 1;
}

return {
  results: sorted,
  total: sorted.length,
  qualified_count: qualCount,
  candidate: {{InstructorLLMNode_426.output.name}}
};
